import RecommendCard from './RecommendCard.jsx';

export default function Features() {
  return (
    <div className="py-20 bg-gray-50 text-center">

      <h2 className="text-3xl font-bold mb-3">
        Core Features
      </h2>

      <p className="text-gray-500 mb-12">
        Powerful tools to simplify your research workflow
      </p>

      <div className="flex justify-center gap-8 flex-wrap">

        {/* Summary */}
        <div className="feature-card-clean">
          <h3>🧠 Summarization</h3>
          <p>Understand papers quickly with AI summaries.</p>
        </div>

        {/* Q&A */}
        <div className="feature-card-clean">
          <h3>💬 Q&A</h3>
          <p>Ask questions directly from your document.</p>
        </div>

        {/* Recommend - Interactive */}
        <RecommendCard />

        {/* 🔥 NEW FEATURE */}
        <div
          className="feature-card-clean cursor-pointer hover:shadow-lg transition"
          onClick={() => {
            document.getElementById("upload-section")?.scrollIntoView({
              behavior: "smooth"
            });
          }}
        >
          <h3>💡 Idea Generator</h3>
          <p>Generate innovative research and project ideas.</p>
        </div>

      </div>
    </div>
  );
}
